from matplotlib import pyplot as pltimport cv2from skimage import io, img_as_floatimg = cv2.imread("../data/BSE_25sigma_noisy.jpg", 0)bilateraL_using_cv2 = cv2.bilateralFilter(img, 5, 20, sigmaSpace =100, borderType = cv2.BORDER_CONSTANT)'''sigmaColor Controls intensity similarity.Small → preserves edges stronglyLarge → smoother/more blursigmaSpace Controls spatial distance influence.Small → only nearby pixels affect filteringLarge → farther pixels also contribute'''from skimage.restoration import denoise_bilateralbilateral_using_skimage = denoise_bilateral(img,sigma_color = 0.05,sigma_spatial = 15)plt.figure()plt.subplot(1,2,1)plt.imshow(bilateraL_using_cv2, cmap = "gray")plt.title("CV2 bilateral")plt.subplot(1,2,2)plt.imshow(bilateral_using_skimage, cmap = "gray")plt.title("Skimage Bilateral")